bevalR.solution:
Inductive bevalR: bexp -> bool -> Prop :=
  | E_BTrue : bevalR BTrue true
  | E_BFalse : bevalR BFalse false
  | E_BEq : forall a1 a2 n1 n2,
      a1 ==> n1 -> a2 ==> n2 -> bevalR (BEq a1 a2) (n1 =? n2)
  | E_BNeq : forall a1 a2 n1 n2,
      a1 ==> n1 -> a2 ==> n2 -> bevalR (BNeq a1 a2) (negb (n1 =? n2))
  | E_BLe : forall a1 a2 n1 n2,
      a1 ==> n1 -> a2 ==> n2 -> bevalR (BLe a1 a2) (n1 <=? n2)
  | E_BGt : forall a1 a2 n1 n2,
      a1 ==> n1 -> a2 ==> n2 -> bevalR (BGt a1 a2) (negb (n1 <=? n2))
  | E_BNot : forall b bv,
      bevalR b bv -> bevalR (BNot b) (negb bv)
  | E_BAnd : forall b1 b2 bv1 bv2,
      bevalR b1 bv1 -> bevalR b2 bv2 -> bevalR (BAnd b1 b2) (andb bv1 bv2)
where "e '==>b' b" := (bevalR e b) : type_scope.

Lemma bevalR_iff_beval : forall b bv,
  b ==>b bv <-> beval b = bv.
Proof.
  split.
  - intros H. induction H; simpl;
      try (apply aevalR_iff_aeval in H; apply aevalR_iff_aeval in H0;
           subst; reflexivity);
      try (rewrite IHbevalR; reflexivity);
      try (rewrite IHbevalR1; rewrite IHbevalR2; reflexivity);
      try reflexivity.
  - generalize dependent bv. induction b; simpl; intros; subst;
      try constructor;
      try (apply aevalR_iff_aeval; reflexivity);
      try (apply IHb; reflexivity);
      try (apply IHb1; reflexivity);
      try (apply IHb2; reflexivity).
Qed.

no_whiles_eqv.solution:
Inductive no_whilesR: com -> Prop :=
  | NW_Skip : no_whilesR <{ skip }>
  | NW_Asgn : forall x a, no_whilesR <{ x := a }>
  | NW_Seq : forall c1 c2, no_whilesR c1 -> no_whilesR c2 -> no_whilesR <{ c1; c2 }>
  | NW_If : forall b c1 c2, no_whilesR c1 -> no_whilesR c2 -> no_whilesR <{ if b then c1 else c2 end }>.

Theorem no_whiles_eqv:
  forall c, no_whiles c = true <-> no_whilesR c.
Proof.
  split.
  - induction c; simpl; intros H;
      try constructor;
      try (apply andb_true_iff in H; destruct H; auto);
      try discriminate.
  - induction c; simpl; intros H;
      try reflexivity;
      try (inversion H; subst; apply andb_true_iff; split; auto);
      inversion H.
Qed.
